al{Z}_i$} \label{full:verif_start} \State{{ f If}\hskip.3em~$ho_j > ho_{(max)}$\hskip.3em~{ f then}\hskip1.0em $ho_{(max)}\!\leftarrow ho_j\hskip.6em and\hskip.6em a(i)\leftarrow j$ } \label{full:verif_end} \EndFor \State{$C_{a(i)}^{[r]}\leftarrow C_{a(i)}^{[r]}\cup\{\hat{ m{x}}_i\}$} \label{full:out_end} \EndFor \end{algorithmic}

