^{}$} \Comment{Region 3} \State{{ f for}\hskip.3em~{ f all}\hskip.3em~$j\in \mathcal{Z}_i$~\hskip.3em{ f do} \hskip1.0em $ho_j\gets ho_j+u_s\cdot w_{(s,j)}$ \label{app_assign:r3_end} } \EndFor \ForAll{$j\in \mathcal{Z}_i$} \label{app_assign:verif_start} \State{{ f If}\hskip.3em~$ho_j > ho_{(max)}$\hskip.3em~{ f then}\hskip1.0em $ho_{(max)}\!\leftarrow ho_j\hskip.6em and\hskip.6em a(i)\leftarrow j$ } \label{app_assign:verif_end} \EndFor \State{$C_{a(i)}^{[r]}\leftarrow C_{a(i)}^{[r]}\cup\{\hat{ m{x}}_i\}$} \label{app_assign:out_end} \EndFor \end{algorithmic}

