ewcommand{\LineFor}[2]{ \State\algorithmicfor\ {#1}\ \algorithmicdo\ {#2} \algorithmicend\ \algorithmic } \caption{\hskip.8em Update step in ES-ICP algorithm} \label{algo:app_update}  egin{algorithmic}[1] \Statex{Input:\hskip.8em $\hat{\mathcal{X}}$,\hskip.5em $\mathcal{C}^{[r]}\!=\!\left\{ C_j^{[r]}ight\}_{j=1}^K$\hskip.5em, \hskip.4em $t^{}$} \Statex{Output:\hskip.8em $ reve{\mathcal{M}}^{[r]}$,~~$ reve{\mathcal{M}}^{p[r]}$,~~ \hskip.3em$\left\{ho_{a(i)}^{[r]}ight\}_{i=1}^N$,\hskip.8em $[\mfH_s]_{s=t^{}}^D$} \ForAll{~$C_j^{[r]}\in \mathcal{C}^{[r]}$~} \label{app_update:outloop} \LineComment{(1) Making tentative mean-feature vector ${ m \lambda}$} \State{$ m{\lambda}\!=\!(\lambda_s)_{s=1}^D\gets  m{0}$} \Comment{Tentative mean-feature vector} \label{app_update:mean_start} \ForAll{~$\hat{ m{x}}_i\!=\!\left[ (t_{(i,p)},u_{t_{(i,p)}})ight]_{p=1}^{(nt)_i}\in C_j^{[r]}$~~} \State{$\lambda_{t_{(i,p)}}\gets \lambda_{t_{(i,p)}}+u_{t_{(i,p)}}$} \EndFor \State{$ m{\lambda}\gets  m{\lambda}/|C_j^{[r]}|$, \hskip.6em $ m{\lambda}\gets$  ramebox[25mm][l]{$ m{\lambda}/(v^{}\cdot \| m{\lambda}\|_2)$}} \Comment{Scaling} \label{app_update:mean_end} \LineComment{(2) Calculating similarities $ho_{a(i)}^{[r]}$} \ForAll{~$\hat{ m{x}}_i\!=\!\left[ (t_{(i,p)},u_{t_{(i,p)}})ight]_{p=1}^{(nt)_i}\in C_j^{[r]}$~~} \label{app_update:asssim_start} \State{$ho_{a(i)}^{[r]}\gets \sum_{p=1}^{(nt)_i} u_{t_{(i,p)}}\cdot \lambda_{t_{(i,p)}}$} \label{app_update:asssim_end} \EndFor \LineComment{(3) Constructing mean-inverted indexes} \ForAll{~term ID $s$ of $\lambda_s > 0$~~} \label{app_update:inv_start} \Comment{Initialize $q\gets 1$} \State{$(c_{(s,q)},v_{c_{(s,q)}})\in reve{\xi}_{s}^{[r]}\subset reve{\mathcal{M}}^{[r]} \gets (j,\lambda_s)$} \Comment{$q\!+\!\!+$} \label{app_update:inv_end} \If{$s\geq t^{}$ and $\lambda_s < v^{}$} \State{$w_{(s,j)}\,(\in  reve{ m \zeta}_s^{[r]}\subset reve{\mathcal{M}}^{p[r]})\,\gets \lambda_s$} \label{app_update:pinv_end} \EndIf \EndFor \EndFor \LineComment{(4) and (5) Structuring $ reve{\xi}_s^{[r]}\in  reve{\mathcal{M}}^{[r]}$} \ForAll{~~$[ reve{\xi}_s^{[r]}]_{s=1}^{t^{}-1}\subset reve{\mathcal{M}}^{[r]}$~~} \label{app_update:strR1_start} \State{Divide $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=1}^{(mf)_s}$ into two blocks:\par \hskip.3em $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=1}^{(mfM)_s}$ and $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=(mfM)_s+1}^{(mf)_s}$\,. } \label{app_update:strR1_end} \EndFor \ForAll{~~$[ reve{\xi}_s^{[r]}]_{s=t^{}}^D\subset reve{\mathcal{M}}^{[r]}$~~} \label{app_update:strR2_start} \State{Pick up tuples from $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=1}^{(mf)_s}\!\in reve{\xi}_s^{[r]}$\par \hskip.5em that satisfy $v_{c_{(s,q)}}\!\geq v^{}$ and\par \hskip.5em make $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=1}^{(mfH)_s}$ from them.} \label{app_update:vth_end} \State{Divide $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=1}^{(mfH)_s}$ into two blocks:\par \hskip.3em $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=1}^{(mfM)_s}$ and $[(c_{(s,q)},v_{c_{(s,q)}})]_{q=(mfM)_s+1}^{(mfH)_s}$.} \label{app_update:strR2_end} \EndFor \LineComment{Estimating structural parameters (Appendices~ef{app:objfunct} and ef{app:est})} \If{$r\in\{1,2\}\;$} \label{app_update:est_start} \State{$(t^{},v^{})\gets$ {\it EstParams}\, ($ reve{\mathcal{M}}^{[r]},\hat{\mathcal{X}}$, other arguments) \par \hskip1.2em(detailed in Appendix~ef{app:est}) } \State{Reconstruct $ reve{\mathcal{M}}^{[r]}$ using new $(t^{},v^{})$} \label{app_update:est_end} \EndIf \end{algorithmic}

