ewcommand{\algto}{to} \algnewcommand{\LineComment}[1]{\Statex \(\hskip.8em	riangleright\) #1} \caption{\hskip.8em Parameter-estimation function: {\it EstParams}} \label{algo:2params}  egin{algorithmic}[1] \Statex{Input:\hskip.5em $ reve{\mathcal{M}}$,\;$\hat{\mathcal{X}}$, \;$ reve{\mathcal{X}}^p$, \;$V^{}=\left\{ v_1^{},\cdots, v_{|V^{}|}^{}ight\}$, \;$s_{(min)}$ } \Statex{Output:\hskip.8em $\left( t^{},\hskip.4em v^{} ight)$} \LineComment{Initialization} \State{$\phi\!=\!\sum_{s=1}^{D} (df)_s\cdot (mf)_s$} \ForAll{$\hat{ m{x}}_i\in \hat{\mathcal{X}}$} \State{ $ ar{ho}_i \gets (1/K)\sum_{p=1}^{(ntH)_i}\sum_{q=1}^{(mf)_{s=t_{(i,p)}}} (v_{c_{(s,q)}}\cdot u_{t_{(i,p)}})$} \EndFor \LineComment{Parallel processing} \ForAll{$v_h^{}\in V^{}$} \label{algo:app_est_outerstart} \State{$	ilde{\phi}_{(D+1,h)}\gets \phi$} \State{$(ntH)_{(i,D+1)}\gets 0,\hskip.5em \Delta v_{(i,D+1)}\gets 0 for\hskip.8em 1\leq i\leq N$} \For{$s'\gets D$\hskip.5em \algto\hskip.5em $s_{(min)}$} \label{algo:app_est_midstart} \Comment{$s'$: $t^{}$ candidate} \ForAll{$i=o_{(s',q')}\in  reve{ m{\eta}}_{s'}\subset  reve{\mathcal{X}}^p$} \label{algo:app_est_innerstart} \State{$	ilde{\phi}_{(s',h)} \gets 	ilde{\phi}_{(s'+1,h)} -(ntH)_{(i,s'+1)}(K/e)^{\gamma_{(i,s'+1)}}$} \State{$\Delta v_{(i,s')} \gets \Delta v_{(i,s'+1)}$\par \hskip\algorithmicindent\hspace*{18mm} $+\sum_{q=(mfH)_s'+1}^{(mf)_{s'}}(v_h^{}-v_{c_{(s',q)}})$\par \hskip\algorithmicindent\hspace*{18mm} $+(K\!-\!(mf)_{s'})\cdot v_h^{} $} \State{$\Delta  ar{v}_{(i,s')} \gets\Delta v_{(i,s')}/K$} \State{$\gamma_{(i,s')}\gets (\Delta ar{v}_{(i,s')}\cdot  reve{u}_i)/(ho_{a(i)}\!-\! ar{ho}_i)$} \State{$	ilde{\phi}_{(s',h)} \gets 	ilde{\phi}_{(s',h)} +(ntH)_{(i,s')}(K/e)^{\gamma_{(i,s')}}$} \label{algo:app_est_innerend} \EndFor \State{$	ilde{\phi}_{(s',h)}\gets 	ilde{\phi}_{(s',h)} -(df)_{s'}\cdot (mfL)_{(s';v_h^{})}$} \State{$J(s',v_h^{}) = 	ilde{\phi}_{(s',h)}$} \label{algo:app_est_midend} \EndFor \State{$(t_h^{},v_h^{})\gets \argmin_{s_{(min)}\leq s' \leq D}~ \left( J(s',v_h^{}) ight)$} \label{algo:app_est_outerend} \EndFor \State{$(t^{},v^{})\gets \argmin_{1\leq h \leq |V^{}|}~ \left( J(t_h^{},v_h^{}) ight)$} \label{algo:app_est_end} \end{algorithmic}

